    }

    @PostMapping("/mark-seen/{userName}")
    public ResponseEntity<Void> markSeen(@PathVariable String userName) {
        // Mặc định là USER gọi API này
        chatService.markSeen(userName, "USER");
        return ResponseEntity.ok().build();
    }

    @PostMapping("/toggle-unread/{partnerName}")
    public ResponseEntity<Void> toggleUnread(@PathVariable String partnerName, @RequestParam boolean isUnread) {
        chatService.toggleManualUnread(partnerName, "USER", isUnread);
        return ResponseEntity.ok().build();
    }

    @GetMapping("/unread-status/{userName}")
    public ResponseEntity<Boolean> getUnreadStatus(@PathVariable String userName) {
        return ResponseEntity.ok(chatService.hasAnyUnreadMessagesForUser(userName));
    }

    @PostMapping("/ai")
    public ResponseEntity<ChatService.AiChatResult> chatWithAi(@RequestBody AiChatRequest request) {
        String message = request != null ? request.getMessage() : "";
        String userName = request != null ? request.getUserName() : null;
        if (message == null || message.isBlank()) {
            return ResponseEntity.ok(new ChatService.AiChatResult(
                    "Xin lỗi, tôi chưa thể trả lời lúc này.",
                    java.util.List.of()
            ));
        }
        return ResponseEntity.ok(chatService.getAiChatReply(message, userName));
    }
}

package com.hcmute.bookstore.Repository;

import com.hcmute.bookstore.Entity.Books;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Repository;

import java.util.List;

@Repository
public interface BooksRepository extends JpaRepository<Books, String> {

    List<Books> findByIsActiveTrue();

    List<Books> findByIsActiveTrueAndCategory_CategoryId(String categoryId);

    List<Books> findByIsActiveTrueOrderBySoldQuantityDesc(Pageable pageable);

    List<Books> findByIsActiveTrueAndCategory_CategoryIdAndBookIdNot(String categoryId, String bookId, Pageable pageable);

    Page<Books> findByTitleContainingIgnoreCase(String title, Pageable pageable);

    Page<Books> findByCategory_CategoryId(String categoryId, Pageable pageable);

    Page<Books> findByTitleContainingIgnoreCaseAndCategory_CategoryId(
            String title,
            String categoryId,
            Pageable pageable
    );

    long countByQuantityLessThanEqual(int quantity);

    @org.springframework.data.jpa.repository.Query(
            "select coalesce(sum(b.quantity), 0) from Books b"
    )
    Long sumStockQuantity();

    @org.springframework.data.jpa.repository.Query(
            "select c.categoryName, count(b) from Books b left join b.category c group by c.categoryName"
    )
    java.util.List<Object[]> countBooksByCategory();
}

package com.hcmute.bookstore.Repository;

import com.hcmute.bookstore.Entity.Books;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Repository;

import java.util.List;

@Repository
public interface BooksRepository extends JpaRepository<Books, String> {

    List<Books> findByIsActiveTrue();

    List<Books> findByIsActiveTrueAndCategory_CategoryId(String categoryId);

    List<Books> findByIsActiveTrueOrderBySoldQuantityDesc(Pageable pageable);

    List<Books> findByIsActiveTrueAndCategory_CategoryIdAndBookIdNot(String categoryId, String bookId, Pageable pageable);

    Page<Books> findByTitleContainingIgnoreCase(String title, Pageable pageable);

    Page<Books> findByCategory_CategoryId(String categoryId, Pageable pageable);

    Page<Books> findByTitleContainingIgnoreCaseAndCategory_CategoryId(
            String title,
            String categoryId,
            Pageable pageable
    );

    long countByQuantityLessThanEqual(int quantity);

    @org.springframework.data.jpa.repository.Query(
            "select coalesce(sum(b.quantity), 0) from Books b"
    )
    Long sumStockQuantity();

    @org.springframework.data.jpa.repository.Query(
            "select c.categoryName, count(b) from Books b left join b.category c group by c.categoryName"
    )
    java.util.List<Object[]> countBooksByCategory();

    @org.springframework.data.jpa.repository.Query(
            """
            select b from Books b
            left join b.category c
            where b.isActive = true
              and b.quantity > 0
              and (
                lower(b.title) like lower(concat('%', :keyword, '%'))
                or lower(b.author) like lower(concat('%', :keyword, '%'))
                or lower(b.description) like lower(concat('%', :keyword, '%'))
                or lower(c.categoryName) like lower(concat('%', :keyword, '%'))
              )
            """
    )
    List<Books> searchForAi(@org.springframework.data.repository.query.Param("keyword") String keyword,
                            org.springframework.data.domain.Pageable pageable);
}

package com.hcmute.bookstore.Service;

import org.springframework.stereotype.Service;

import java.text.Normalizer;
import java.util.List;

@Service
public class ChatIntentService {

    public enum Intent {
        BOOK_SEARCH,
        ORDER_SUPPORT,
        GENERAL_CHAT,
        OUT_OF_SCOPE
    }

    public Intent detectIntent(String message) {
        if (message == null || message.isBlank()) {
            return Intent.OUT_OF_SCOPE;
        }

        String normalized = normalize(message);

        if (containsAny(normalized, List.of(
                "don hang", "kiem tra don", "huy don", "tra hang", "giao hang", "van chuyen", "order"
        ))) {
            return Intent.ORDER_SUPPORT;
        }

        if (containsAny(normalized, List.of(
                "chao", "xin chao", "hello", "hi", "ban la ai", "cam on", "hom nay", "ban khoe"
        ))) {
            return Intent.GENERAL_CHAT;
        }

        if (containsAny(normalized, List.of(
                "sach", "book", "truyen", "tieu thuyet", "trinh tham", "self help", "selfhelp",
                "lap trinh", "java", "python", "cam dong", "buon", "tinh cam", "ky nang", "kinh te",
                "mystery", "detective", "crime", "suspense", "investigation"
        ))) {
            return Intent.BOOK_SEARCH;
        }

        return Intent.OUT_OF_SCOPE;
    }

    private String normalize(String input) {
        String noAccent = Normalizer.normalize(input, Normalizer.Form.NFD)
                .replaceAll("\\p{M}+", "");
        return noAccent.toLowerCase();
    }

    private boolean containsAny(String normalized, List<String> patterns) {
        for (String pattern : patterns) {
            if (normalized.contains(pattern)) {
                return true;
            }
        }
        return false;
    }
}

package com.hcmute.bookstore.Service;

import com.hcmute.bookstore.Entity.Books;
import com.hcmute.bookstore.Repository.BooksRepository;
import lombok.RequiredArgsConstructor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.PageRequest;
import org.springframework.stereotype.Service;

import java.text.Normalizer;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Locale;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;

@Service
@RequiredArgsConstructor
public class ChatResponseService {
    private static final Logger log = LoggerFactory.getLogger(ChatResponseService.class);

    private static final String ANON_USER = "anonymous";
    private static final ConcurrentHashMap<String, ChatContext> CONTEXTS = new ConcurrentHashMap<>();

    private final ChatIntentService chatIntentService;
    private final BooksRepository booksRepository;
    private final GeminiService geminiService;

    public ChatService.AiChatResult respond(String message) {
        return respond(message, null);
    }

    public ChatService.AiChatResult respond(String message, String userName) {
        String text = message != null ? message.trim() : "";
        String userKey = (userName == null || userName.isBlank()) ? ANON_USER : userName.trim();
        if (text.isBlank()) {
            return new ChatService.AiChatResult("Xin lỗi, tôi chưa thể trả lời lúc này.", List.of());
        }

        ChatContext context = CONTEXTS.getOrDefault(userKey, ChatContext.empty());
        ChatIntentService.Intent intent = chatIntentService.detectIntent(text);
        log.info("AI_CHAT message='{}' intent={} user={}", text, intent, userKey);

        if (isNegativeFeedback(text) && context.lastTopic() != null) {
            ChatService.AiChatResult retry = handleBookSearch(text, context.lastTopic(), true, userKey);
            String reply = "Bạn nói đúng  mấy cuốn trước chưa sát. Để mình gợi ý lại chuẩn hơn nhé:\n" + retry.reply();
            return new ChatService.AiChatResult(reply, retry.books());
        }

        if (intent != ChatIntentService.Intent.BOOK_SEARCH && context.lastTopic() != null && isRefinementQuery(text)) {
            return handleBookSearch(text, context.lastTopic(), true, userKey);
        }

        return switch (intent) {
            case BOOK_SEARCH -> handleBookSearch(text, null, false, userKey);
            case ORDER_SUPPORT -> new ChatService.AiChatResult(
                    "Bạn vui lòng vào mục Đơn hàng để kiểm tra trạng thái đơn nhé.",
                    List.of()
            );
            case GENERAL_CHAT -> new ChatService.AiChatResult(
                    "Mình là trợ lý AI của nhà sách, có thể giúp bạn tìm sách và hỗ trợ mua hàng.",
                    List.of()
            );
            case OUT_OF_SCOPE -> new ChatService.AiChatResult(
                    buildOutOfScopeReply(text),
                    List.of()
            );
        };
    }

    private ChatService.AiChatResult handleBookSearch(String text) {
        return handleBookSearch(text, null, false, ANON_USER);
    }

    private ChatService.AiChatResult handleBookSearch(String text, String forcedTopic, boolean strict, String userKey) {
        String topic = forcedTopic != null && !forcedTopic.isBlank() ? forcedTopic : extractTopic(text);
        List<Books> candidates = findAiCandidates(text);
        if (candidates.isEmpty()) {
            candidates = booksRepository.findByIsActiveTrue().stream()
                    .filter(b -> b.getQuantity() > 0)
                    .limit(50)
                    .toList();
        }

        List<String> topicKeywords = topicKeywords(topic);
        if (!topicKeywords.isEmpty()) {
            candidates = filterByTopic(candidates, topicKeywords);
        }

        if (candidates.isEmpty()) {
            return new ChatService.AiChatResult(
                    "Hiện tại mình chưa tìm thấy sách phù hợp, bạn thử từ khóa khác nhé.",
                    List.of()
            );
        }

        boolean useGemini = shouldUseGemini(text);
        GeminiService.GeminiResult parsed = useGemini
                ? geminiService.generateRecommendations(text, candidates)
                : new GeminiService.GeminiResult("", List.of());

        List<Books> picked = candidates.stream()
                .filter(b -> parsed.bookIds().contains(String.valueOf(b.getBookId())))
                .limit(5)
                .toList();

        if (picked.isEmpty()) {
            picked = candidates.stream().limit(5).toList();
        }

        String reply = parsed.reply() != null ? parsed.reply().trim() : "";
        if (reply.isBlank()) {
            if (useGemini) {
                reply = "AI đang bận, mình gợi ý nhanh vài sách cho bạn nhé:";
            } else if (topic != null && !topic.isBlank()) {
                reply = "Mình tìm được vài sách " + topic + " phù hợp cho bạn:";
            } else {
                reply = "Mình tìm được vài sách phù hợp cho bạn:";
            }
        }

        List<ChatService.AiBookResult> books = picked.stream()
                .map(b -> new ChatService.AiBookResult(
                        b.getBookId(),
                        b.getTitle(),
                        b.getAuthor(),
                        b.getPrice(),
                        b.getPicture()
                ))
                .toList();

        rememberContext(userKey, topic, books, strict);
        log.info("AI_CHAT_RESULT books_found={} used_gemini={} topic='{}' reply='{}'", books.size(), useGemini, topic, reply);
        return new ChatService.AiChatResult(reply, books);
    }

    private void rememberContext(String userKey, String topic, List<ChatService.AiBookResult> books, boolean strict) {
        if (topic == null || topic.isBlank()) {
            return;
        }
        String key = (userKey == null || userKey.isBlank()) ? ANON_USER : userKey.trim();
        CONTEXTS.put(key, new ChatContext(topic, books.size(), strict));
    }

    private List<Books> findAiCandidates(String message) {
        List<String> keywords = new java.util.ArrayList<>(extractKeywords(message, false));
        for (String keyword : extractKeywords(message, true)) {
            if (!keywords.contains(keyword)) {
                keywords.add(keyword);
            }
        }
        if (keywords.isEmpty()) {
            keywords = List.of(message);
        }

        LinkedHashMap<String, Books> collected = new LinkedHashMap<>();
        for (String keyword : keywords) {
            List<Books> found = booksRepository.searchForAi(keyword, PageRequest.of(0, 30));
            for (Books book : found) {
                collected.putIfAbsent(String.valueOf(book.getBookId()), book);
                if (collected.size() >= 80) {
                    break;
                }
            }
            if (collected.size() >= 80) {
                break;
            }
        }

        log.info("AI_CHAT_CANDIDATES keywords={} count={}", keywords, collected.size());
        return new ArrayList<>(collected.values());
    }

    private List<Books> filterByTopic(List<Books> candidates, List<String> topicKeywords) {
        return candidates.stream()
                .filter(book -> matchesTopic(book, topicKeywords))
                .toList();
    }

    private boolean matchesTopic(Books book, List<String> topicKeywords) {
        String text = normalize((book.getTitle() != null ? book.getTitle() : "") + " " +
                (book.getDescription() != null ? book.getDescription() : "") + " " +
                (book.getCategory() != null ? book.getCategory().getCategoryName() : ""));
        for (String keyword : topicKeywords) {
            if (text.contains(keyword)) {
                return true;
            }
        }
        return false;
    }

    private List<String> topicKeywords(String topic) {
        if (topic == null || topic.isBlank()) {
            return List.of();
        }
        String normalized = normalize(topic);
        if (normalized.contains("trinh tham")) {
            return List.of("trinh tham", "mystery", "detective", "crime", "suspense", "investigation");
        }
        if (normalized.contains("self help") || normalized.contains("selfhelp")) {
            return List.of("self help", "selfhelp", "ky nang", "phat trien");
        }
        if (normalized.contains("tinh cam")) {
            return List.of("tinh cam", "romance", "love", "lang man");
        }
        if (normalized.contains("buon") || normalized.contains("cam dong")) {
            return List.of("cam dong", "buon", "chua lanh", "healing");
        }
        if (normalized.contains("lap trinh") || normalized.contains("java") || normalized.contains("python")) {
            return List.of("lap trinh", "java", "python", "coding", "programming");
        }
        return List.of(normalized);
    }

    private boolean isNegativeFeedback(String message) {
        String normalized = normalize(message);
        return containsAny(normalized, List.of(
                "khong dung y", "khong dung", "chua chuan", "sai the loai", "do dau phai",
                "khong phai", "sach khac", "khong giong", "khong dung the loai", "chua dung"
        ));
    }

    private boolean isRefinementQuery(String message) {
        String normalized = normalize(message);
        return containsAny(normalized, List.of(
                "viet nam", "ngan", "ngan thoi", "ngan gon", "loai", "plot twist", "buon hon",
                "nghe", "de doc", "kho", "sau sac", "co that", "gan day"
        ));
    }

    private String buildOutOfScopeReply(String message) {
        String normalized = normalize(message);
        if (containsAny(normalized, List.of("bun bo", "pho", "an", "mon", "nau", "do an"))) {
            return "Mình hiểu là bạn đang thèm món đó  tiếc là mình chuyên hỗ trợ sách và đơn hàng. Nếu bạn muốn tìm truyện hay thì mình giúp ngay.";
        }
        if (containsAny(normalized, List.of("thoi tiet", "hom nay", "troi", "mua", "nang"))) {
            return "Hôm nay thời tiết thế nào cũng đáng để đọc một cuốn sách hay  Mình có thể gợi ý sách phù hợp cho bạn.";
        }
        if (containsAny(normalized, List.of("choi game", "game", "giai tri"))) {
            return "Nghe vui đó  nhưng mình chuyên hỗ trợ sách và đơn hàng. Nếu bạn muốn tìm sách giải trí hay thì mình sẵn sàng.";
        }
        return "Mình hiểu ý bạn, nhưng hiện mình chuyên hỗ trợ sách và đơn hàng. Nếu bạn muốn gợi ý sách hay thì mình sẵn sàng nhé ";
    }

    private List<String> extractKeywords(String message, boolean normalizeMessage) {
        String source = normalizeMessage ? normalize(message) : message.toLowerCase(Locale.ROOT);
        String[] parts = source.split("[^\\p{L}\\p{N}]+");
        Set<String> stopWords = Set.of(
                "toi", "muon", "can", "tim", "sach", "ve", "the", "loai", "goi", "y",
                "hay", "cho", "minh", "ban", "nhung", "nhieu", "nao", "mot", "xin"
        );
        List<String> keywords = new ArrayList<>();
        for (String part : parts) {
            if (part.length() < 2) continue;
            String normalizedPart = normalize(part);
            if (stopWords.contains(normalizedPart)) continue;
            keywords.add(part);
            if (keywords.size() >= 6) break;
        }
        return keywords;
    }

    private boolean shouldUseGemini(String message) {
        String normalized = normalize(message);
        List<String> tokens = extractKeywords(normalized, false);
        boolean isShort = tokens.size() <= 2 && normalized.length() <= 24;
        boolean looksSimple = containsAny(normalized, List.of(
                "trinh tham", "self help", "selfhelp", "tinh cam", "buon", "cam dong",
                "lap trinh", "java", "python", "tieu thuyet", "thieu nhi", "kinh te"
        ));
        return !(isShort || looksSimple);
    }

    private List<String> extractKeywords(String message) {
        return extractKeywords(message, true);
    }

    private String extractTopic(String message) {
        String normalized = normalize(message);
        if (normalized.contains("trinh tham")) return "trinh thám";
        if (normalized.contains("self help") || normalized.contains("selfhelp")) return "self-help";
        if (normalized.contains("buon") || normalized.contains("cam dong")) return "cảm động";
        if (normalized.contains("lap trinh") || normalized.contains("java") || normalized.contains("python")) return "lập trình";
        if (normalized.contains("tinh cam")) return "tình cảm";
        if (normalized.contains("tieu thuyet")) return "tiểu thuyết";
        return "";
    }

    private String normalize(String input) {
        String noAccent = Normalizer.normalize(input, Normalizer.Form.NFD)
                .replaceAll("\\p{M}+", "");
        return noAccent.toLowerCase(Locale.ROOT).trim();
    }

    private boolean containsAny(String normalized, List<String> patterns) {
        for (String pattern : patterns) {
            if (normalized.contains(pattern)) {
                return true;
            }
        }
        return false;
    }

    private record ChatContext(String lastTopic, int lastBookCount, boolean strictMode) {
        private static ChatContext empty() {
            return new ChatContext(null, 0, false);
        }
    }
}

package com.hcmute.bookstore.Service;

import com.hcmute.bookstore.Entity.ChatMessage;
import com.hcmute.bookstore.Entity.MessageStatus;
import com.hcmute.bookstore.Entity.Orders;
import com.hcmute.bookstore.Repository.ChatMessageRepository;
import com.hcmute.bookstore.dto.ChatMessageResponse;
import com.hcmute.bookstore.dto.admin.ChatThreadDTO;
import lombok.RequiredArgsConstructor;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
public class ChatService {
    @Autowired
    private ChatMessageRepository chatRepository;

    public ChatMessageResponse mapToResponse(ChatMessage entity) {
        ChatMessageResponse.ChatMessageResponseBuilder builder = ChatMessageResponse.builder()
                .id(entity.getId())
                .content(entity.getContent())
                .mediaUrl(entity.getMediaUrl())
                .messageType(entity.getMessageType())
                .userName(entity.getUserName())
                .senderRole(entity.getSenderRole())
                .receiverName(entity.getReceiverName())
                .createdAt(entity.getCreatedAt())
                .isMarkedUnreadByAdmin(entity.isMarkedUnreadByAdmin())
                .isMarkedUnreadByUser(entity.isMarkedUnreadByUser());

        if (entity.getReplyTo() != null) {
            builder.replyToId(entity.getReplyTo().getId());
            builder.replyToContent(entity.getReplyTo().getContent());
            builder.replyToMediaUrl(entity.getReplyTo().getMediaUrl());
            builder.replyToMessageType(entity.getReplyTo().getMessageType());
            builder.replyToSender(entity.getReplyTo().getUserName());
        }

        if (entity.getAttachedBook() != null) {
            builder.bookId(entity.getAttachedBook().getBookId());
            builder.bookName(entity.getAttachedBook().getTitle());
            builder.bookImage(entity.getAttachedBook().getPicture());
            builder.bookPrice(entity.getAttachedBook().getPrice());
        }

        // CẬP NHẬT PHẦN MAP ORDER TẠI ĐÂY
        if (entity.getAttachedOrder() != null) {
            Orders order = entity.getAttachedOrder();
            builder.orderId(order.getOrderId());
            builder.orderStatus(order.getStatus().toString());
            builder.totalPrice(order.getTotalAmount());

            // Lấy số mặt hàng từ danh sách chi tiết đơn hàng
            if (order.getOrderDetail_Order() != null) {
                builder.orderItemCount(order.getOrderDetail_Order().size());
            } else {
                builder.orderItemCount(0);
            }

            // LẤY TẤM HÌNH ĐẦU TIÊN Ở ĐÂY
            // Lấy item đầu tiên -> lấy Book -> lấy Picture
            String firstProductImage = order.getOrderDetail_Order().get(0).getBook().getPicture();
            builder.bookImage(firstProductImage);
        }

        if (entity.getReaction() != null) {
            builder.reaction(entity.getReaction().name());
        }

        return builder.build();
    }

    // Lấy danh sách thread cho Admin kèm unread count và manual flag
    public List<ChatThreadDTO> getChatThreadsForAdmin() {
        List<ChatMessage> latestMessages = chatRepository.findAllChatThreads();
        return latestMessages.stream().map(msg -> {
            long unreadCount = chatRepository.countByUserNameAndReceiverNameAndStatusNot(msg.getUserName(), "admin", MessageStatus.SEEN);
            return ChatThreadDTO.builder()
                    .customerUsername(msg.getUserName())
                    .lastMessage(msg.getContent())
                    .lastTime(msg.getCreatedAt())
                    .unreadCount((int) unreadCount)
                    .manualUnread(msg.isMarkedUnreadByAdmin())
                    .build();
        }).collect(Collectors.toList());
    }

    // Đánh dấu đã xem
    @Transactional
    public void markSeen(String partnerName, String role) {
        if ("ADMIN".equalsIgnoreCase(role)) {
            chatRepository.markAllAsSeenByAdmin(partnerName);
        } else {
            chatRepository.markAllAsSeenByUser(partnerName);
        }
    }

    // Bật/tắt đánh dấu chưa đọc thủ công
    @Transactional
    public void toggleManualUnread(String customerUsername, String role, boolean isUnread) {
        if ("ADMIN".equalsIgnoreCase(role)) {
            ChatMessage latestMsg = chatRepository.findFirstByUserNameAndReceiverNameOrderByCreatedAtDesc(customerUsername, "admin");
            if (latestMsg != null) {
                latestMsg.setMarkedUnreadByAdmin(isUnread);
                chatRepository.save(latestMsg);
            }
        } else {
            ChatMessage latestMsg = chatRepository.findFirstByUserNameAndReceiverNameOrderByCreatedAtDesc("admin", customerUsername);
            if (latestMsg != null) {
                latestMsg.setMarkedUnreadByUser(isUnread);
                chatRepository.save(latestMsg);
            }
        }
    }

    // --- Legacy and other methods ---
    public List<ChatMessage> getChatThreads() { return chatRepository.findAllChatThreads(); }
    public List<ChatMessageResponse> getChatHistory(String userName) {
        return chatRepository.findByUserNameOrderByCreatedAtAsc(userName)
                .stream().map(this::mapToResponse).collect(Collectors.toList());
    }
    public ChatMessage saveMessage(ChatMessage message) { return chatRepository.save(message); }
    public void markSeenByAdmin(String customerUsername) { chatRepository.markAllAsSeenByAdmin(customerUsername); }
    public void toggleManualUnreadByAdmin(String customerUsername, boolean isUnread) { toggleManualUnread(customerUsername, "ADMIN", isUnread); }

    public boolean hasAnyUnreadMessagesForAdmin() {
        return chatRepository.existsUnreadForAdmin();
    }

    public boolean hasAnyUnreadMessagesForUser(String userName) {
        return chatRepository.existsUnreadForUser(userName);
    }
}

